import random, itertools, math, numpy as np
def prob_bad(weights,p):
    n=len(weights)
    prob=0.0
    for mask in range(1<<n):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; k+=1
        if s < p-1e-12:
            prob += (p**k)*((1-p)**(n-k))
    return prob
