def is_shifted(D,n):
    D=set(D)
    for S in D:
        for j in range(n):
            if (S>>j)&1:
                for i in range(j):
                    if not ((S>>i)&1):
                        T=(S & ~(1<<j)) | (1<<i)
                        if T not in D:
                            return False
    return True
