from functools import lru_cache
def gen_downsets(n):
    # recursive: downset D in n dims = E (without n) union {A+n: A in F}, F subset E downsets in n-1
    if n==0:
        yield frozenset([0])  # only subset of empty? downset can be empty too? Include empty family too.
        yield frozenset()
        return
    # better generate all pairs F⊂E downsets of n-1
    prev=list(gen_downsets(n-1))
    for E in prev:
        for F in prev:
            if F.issubset(E):
                D=set(E)
                for A in F:
                    D.add(A | (1<<(n-1)))
                yield frozenset(D)
